import { derivationConfig } from "./nix_derivation_config";

/**
 * Renders the Nix derivation for promptnotes as a string.
 * Run with `npx tsx generate_nix.ts > nix/default.nix` from the project root.
 *
 * The derivation targets Linux and macOS only (platform:linux, platform:macos).
 * Windows is not supported and is intentionally excluded from `meta.platforms`.
 *
 * The build uses:
 *   - rustPlatform.buildRustPackage for the Tauri (Rust) backend (framework:tauri)
 *   - pnpm (via pnpm.configHook) + vite for the Svelte frontend
 *   - cargo-tauri to assemble and bundle the final application
 */
function renderNixDerivation(): string {
  const cfg = derivationConfig;

  const linuxInputs = cfg.buildInputs.linux.join("\n    ");
  const darwinInputs = cfg.buildInputs.darwin.join("\n    ");
  const commonInputs = cfg.buildInputs.common.join("\n    ");
  const nativeInputs = cfg.nativeBuildInputs.join("\n    ");
  const linuxRuntime = cfg.runtimeDependencies.linux.join("\n    ");

  return `# This file is generated by src/generated/sprint_58/task_58_1/generate_nix.ts.
# Do not edit manually — regenerate via \`npx tsx generate_nix.ts > nix/default.nix\`.
#
# Targets: platform:linux, platform:macos
# Framework: Tauri (Rust + OS WebView) — RBC-1

{
  lib,
  rustPlatform,
  fetchFromGitHub,
  pkg-config,
  nodejs,
  pnpm,
  cargo-tauri,
  stdenv,
  # Linux-specific
  webkitgtk_4_1,
  gtk3,
  libsoup_3,
  glib,
  cairo,
  pango,
  atk,
  gdk-pixbuf,
  openssl,
  librsvg,
  dbus,
  at-spi2-atk,
  xdg-utils,
  wrapGAppsHook,
  # macOS-specific
  darwin,
  libiconv,
}:

rustPlatform.buildRustPackage rec {
  pname = "${cfg.pname}";
  version = "${cfg.version}";

  src = ../..;  # project root relative to nix/default.nix

  cargoHash = "${cfg.cargoHash}";

  # pnpm lockfile hash — update after changing package.json / pnpm-lock.yaml.
  pnpmDeps = pnpm.fetchDeps {
    inherit pname version src;
    hash = "${cfg.npmDepsHash}";
  };

  nativeBuildInputs = [
    ${nativeInputs}
    cargo-tauri.hook
  ];

  buildInputs =
    lib.optionals stdenv.isLinux [
      ${linuxInputs}
    ]
    ++ lib.optionals stdenv.isDarwin [
      ${darwinInputs}
    ]
    ++ [
      ${commonInputs}
    ];

  # Tauri reads TAURI_SKIP_DEVSERVER_CHECK to avoid blocking on the dev server
  # during the production (nix) build.
  env = {
    TAURI_SKIP_DEVSERVER_CHECK = "true";
    ${Object.entries(cfg.env)
      .map(([k, v]) => `${k} = "${v}";`)
      .join("\n    ")}
  };

  buildAndTestSubdir = "src-tauri";

  # Frontend must be compiled before cargo-tauri bundles the app.
  preBuild = ''
    pnpm build
  '';

  postInstall = lib.optionalString stdenv.isLinux ''
    # Wrap the binary so it can locate WebKitGTK / GTK runtime libs.
    wrapProgram $out/bin/${cfg.pname} \\
      --prefix XDG_DATA_DIRS : "$XDG_ICON_DIRS:${`\${gtk3}/share/gsettings-schemas/\${gtk3.name}`}"
  '';

  # Propagate shared runtime libs on Linux so the app finds dbus, at-spi2-atk etc.
  ${
    linuxRuntime
      ? `depsTargetTarget = lib.optionals stdenv.isLinux [
    ${linuxRuntime}
  ];`
      : ""
  }

  meta = with lib; {
    description = "${cfg.description}";
    longDescription = ''${cfg.meta.longDescription.trim()}'';
    homepage = "${cfg.homepage}";
    license = licenses.mit;
    maintainers = [];
    mainProgram = "${cfg.meta.mainProgram}";
    # Windows is explicitly out of scope (platform:linux + platform:macos only).
    platforms = [ ${cfg.platforms.map((p) => `"${p}"`).join(" ")} ];
  };
}
`;
}

// When executed directly, print the derivation to stdout.
if (require.main === module) {
  process.stdout.write(renderNixDerivation());
}

export { renderNixDerivation };
